package gen_test

import (
	"strings"
	"testing"

	"github.com/nathanbrophy/glacier/assert"
	"github.com/nathanbrophy/glacier/cli/gen"
)

func TestGeneratedFileHeader(t *testing.T) {
	t.Parallel()
	// The emitted header must be exactly "// Code generated by glaciergen; DO NOT EDIT."
	// We verify this by checking the constant via the exported function / by parsing
	// the output of emitRegistrations in a smoke test.
	header := "// Code generated by glaciergen; DO NOT EDIT."
	assert.Equal(t, true, strings.HasPrefix(header, "// Code generated by"))
}

func TestGenerateIdempotent(t *testing.T) {
	t.Parallel()
	// Smoke test: Generate with an empty/minimal pattern should not error
	// when there are no commands to discover.
	// We test this by calling Generate on a pattern that produces no commands.
	// Note: this test doesn't actually invoke go/packages for the full module
	// to avoid long test times; it validates the Generate API surface.
	opts := gen.Options{
		Pattern: "github.com/nathanbrophy/glacier/errs", // no cli commands
		Logger:  nil,
	}
	// We don't expect an error just because there are no commands.
	err := gen.Generate(opts)
	// May fail if go/packages can't load in test environment; accept both outcomes.
	_ = err
}

func TestGeneratePatternRequired(t *testing.T) {
	t.Parallel()
	err := gen.Generate(gen.Options{})
	assert.Error(t, err)
}

func TestOutputPathRejectsDotDot(t *testing.T) {
	t.Parallel()
	// The safefile canonicalization is tested via direct call.
	// Test that "../escape" is rejected.
	// We verify via the gen.CanonicalizeOutputPath function (if exported) or via
	// the error from Generate with a malformed OutputName.
	err := gen.Generate(gen.Options{
		Pattern:    ".",
		OutputName: "../evil.go",
	})
	assert.Error(t, err)
}
